import requests

def test_add_beneficiary_with_malformed_account_number_returns_400(
    api_base_url, auth_token
):
    payload = {
        "name": "Bad Account",
        "account_number": "ABC@#$%XYZ",
        "bank_code": "TEST",
        "account_type": "checking"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}

    resp = requests.post(
        f"{api_base_url}/beneficiaries",
        json=payload,
        headers=headers
    )

    assert resp.status_code == 400
    body = resp.json()
    assert "account_number" in body.get("errors", {})
    assert body["error_code"] == "INVALID_ACCOUNT_NUMBER"
